// Generate plugin content from template.
// In local-dev mode the command uses the `directory` variable that OpenCode
// passes to the plugin, so the JS constant must be a template literal (backticks)
// rather than a double-quoted string.
var content string
if localDev {
	// Replace the entire quoted placeholder with a template literal.
	content = strings.ReplaceAll(
		pluginTemplate,
		`"`+entireCmdPlaceholder+`"`,
		"`go run ${directory}/cmd/entire/main.go`",
	)
} else {
	content = strings.ReplaceAll(pluginTemplate, entireCmdPlaceholder, "entire")
}

