	content := string(data)
	if !strings.Contains(content, "go run") {
		t.Error("local dev mode: plugin file should contain 'go run'")
	}
	// Should use a template literal with ${directory} for runtime resolution
	if !strings.Contains(content, "${directory}/cmd/entire/main.go") {
		t.Error("local dev mode: plugin file should reference ${directory}/cmd/entire/main.go")
